// Step 1: Validate required fields from intake payload
const data = $input.first().json;

const requiredFields = [
  'full_name',
  'personal_email', 
  'job_title',
  'department',
  'start_date',
  'manager_name'
];

const missingFields = requiredFields.filter(field => !data[field] || data[field] === '');
const validationScore = ((requiredFields.length - missingFields.length) / requiredFields.length) * 100;

return [{
  json: {
    ...data,
    validation_passed: validationScore >= 85,
    validation_score: validationScore,
    missing_required_fields: missingFields,
    intake_timestamp: new Date().toISOString(),
    record_id: `ONB-${Date.now()}`
  }
}];

