// Step 3: Parse AI output and enrich with role-based onboarding track
const aiOutput = $input.first().json;
let extracted;

try {
  // Handle both direct JSON and nested message format
  if (aiOutput.choices && aiOutput.choices[0]) {
    extracted = JSON.parse(aiOutput.choices[0].message.content);
  } else {
    extracted = aiOutput;
  }
} catch(e) {
  extracted = aiOutput;
}

// Role-based onboarding tracks
const departmentTracks = {
  'Engineering': {
    tools: ['GitHub', 'Jira', 'Slack', 'VS Code', 'AWS Console'],
    training: ['Security & Compliance', 'Code Review Standards', 'Architecture Overview', 'Dev Environment Setup'],
    priority_tasks: ['Set up dev environment', 'Join engineering Slack channels', 'Complete security training', 'Meet with tech lead']
  },
  'Sales': {
    tools: ['Salesforce CRM', 'Outreach', 'LinkedIn Sales Navigator', 'Slack', 'Zoom'],
    training: ['Product Demo Certification', 'Sales Methodology', 'CRM Training', 'Compliance Training'],
    priority_tasks: ['Complete CRM setup', 'Shadow 3 sales calls', 'Review sales playbook', 'Meet with account executives']
  },
  'HR': {
    tools: ['BambooHR', 'Slack', 'Google Workspace', 'DocuSign', 'Notion'],
    training: ['HRIS Training', 'Compliance & Privacy', 'Benefits Administration', 'Recruitment Process'],
    priority_tasks: ['Complete HRIS access setup', 'Review HR policies', 'Meet HR team members', 'Complete compliance training']
  },
  'default': {
    tools: ['Slack', 'Google Workspace', 'Notion', 'Zoom'],
    training: ['Company Overview', 'Security & Compliance', 'Tool Access Training'],
    priority_tasks: ['Complete system access setup', 'Review company handbook', 'Attend orientation', 'Meet your team']
  }
};

const dept = extracted.department || 'default';
const track = departmentTracks[dept] || departmentTracks['default'];

return [{
  json: {
    ...extracted,
    onboarding_track: track,
    profile_enriched_at: new Date().toISOString(),
    status: 'profile_ready',
    record_id: $('Validate Intake Record').first().json.record_id
  }
}];

